const customer = $input.item(0)?.json || $input.item(1)?.json?.[0];
const conversations = $input.item(1)?.json || [];

if (!customer) {
  return [{ json: { memory: 'New customer — no prior history.', isNew: true } }];
}

const sections = [];

if (customer.name) sections.push(`Name: ${customer.name}`);
if (customer.profile_summary) sections.push(`Profile: ${customer.profile_summary}`);
if (customer.language) sections.push(`Language: ${customer.language}`);
if (customer.total_conversations > 1) sections.push(`Returning customer (${customer.total_conversations} conversations since ${new Date(customer.first_contact).toLocaleDateString()})`);

const prefs = customer.preferences || {};
if (Object.keys(prefs).length > 0) {
  sections.push(`Preferences: ${JSON.stringify(prefs)}`);
}

const events = customer.key_events || [];
if (events.length > 0) {
  sections.push(`Recent history:\n${events.slice(-5).map(e => `- ${e.date}: ${e.summary}`).join('\n')}`);
}

if (customer.tags && customer.tags.length > 0) {
  sections.push(`Tags: ${customer.tags.join(', ')}`);
}

if (customer.notes) {
  sections.push(`Notes: ${customer.notes}`);
}

if (Array.isArray(conversations) && conversations.length > 0) {
  sections.push(`\nPast conversations:\n${conversations.map(c => `- ${new Date(c.started_at).toLocaleDateString()}: ${c.summary}`).join('\n')}`);
}

return [{ json: {
  memory: sections.join('\n'),
  customerId: customer.id,
  isNew: customer.total_conversations <= 1,
  isVip: customer.tags?.includes('vip'),
  sentiment: customer.avg_sentiment
}}];
